+// ─── Lighting system ────────────────────────────────────────────────
+
+/**
+ * Draw a warm torch glow radial gradient at (x, y) with flickering radius.
+ * @param ctx CanvasRenderingContext2D
+ * @param x X coordinate of torch center
+ * @param y Y coordinate of torch center
+ * @param baseRadius Base radius of glow circle
+ * @param frame Current animation frame number for flicker
+ */
+function drawTorchGlow(ctx: CanvasRenderingContext2D, x: number, y: number, baseRadius: number, frame: number) {
+  // Flicker radius ±2 px
+  const flicker = 2 * Math.sin(frame * 0.15 + x + y);
+  const radius = baseRadius + flicker;
+
+  const gradient = ctx.createRadialGradient(x, y, radius * 0.1, x, y, radius);
+  gradient.addColorStop(0, 'rgba(255, 200, 100, 0.8)'); // bright warm core
+  gradient.addColorStop(0.3, 'rgba(255, 160, 50, 0.4)');
+  gradient.addColorStop(0.7, 'rgba(255, 120, 20, 0.15)');
+  gradient.addColorStop(1, 'rgba(255, 80, 0, 0)');
+
+  ctx.fillStyle = gradient;
+  ctx.beginPath();
+  ctx.arc(x, y, radius, 0, Math.PI * 2);
+  ctx.fill();
+}
+
+/**
+ * Draw lighting for the room including torches and corner shadows.
+ * Place 2 torches on walls per room.
+ * @param ctx CanvasRenderingContext2D
+ * @param type Room character type
+ * @param x Room top-left x
+ * @param y Room top-left y
+ * @param w Room width
+ * @param h Room height
+ * @param frame Current animation frame number
+ */
+function drawRoomLighting(ctx: CanvasRenderingContext2D, type: CharacterType, x: number, y: number, w: number, h: number, frame: number) {
+  // Draw darker corners
+  const cornerRadius = 40;
+  const cornerGradientTL = ctx.createRadialGradient(x, y, 0, x, y, cornerRadius);
+  cornerGradientTL.addColorStop(0, 'rgba(0,0,0,0.6)');
+  cornerGradientTL.addColorStop(1, 'rgba(0,0,0,0)');
+  ctx.fillStyle = cornerGradientTL;
+  ctx.fillRect(x, y, cornerRadius, cornerRadius);
+
+  const cornerGradientTR = ctx.createRadialGradient(x + w, y, 0, x + w, y, cornerRadius);
+  cornerGradientTR.addColorStop(0, 'rgba(0,0,0,0.6)');
+  cornerGradientTR.addColorStop(1, 'rgba(0,0,0,0)');
+  ctx.fillStyle = cornerGradientTR;
+  ctx.fillRect(x + w - cornerRadius, y, cornerRadius, cornerRadius);
+
+  const cornerGradientBL = ctx.createRadialGradient(x, y + h, 0, x, y + h, cornerRadius);
+  cornerGradientBL.addColorStop(0, 'rgba(0,0,0,0.6)');
+  cornerGradientBL.addColorStop(1, 'rgba(0,0,0,0)');
+  ctx.fillStyle = cornerGradientBL;
+  ctx.fillRect(x, y + h - cornerRadius, cornerRadius, cornerRadius);
+
+  const cornerGradientBR = ctx.createRadialGradient(x + w, y + h, 0, x + w, y + h, cornerRadius);
+  cornerGradientBR.addColorStop(0, 'rgba(0,0,0,0.6)');
+  cornerGradientBR.addColorStop(1, 'rgba(0,0,0,0)');
+  ctx.fillStyle = cornerGradientBR;
+  ctx.fillRect(x + w - cornerRadius, y + h - cornerRadius, cornerRadius, cornerRadius);
+
+  // Torch positions: place 2 torches on walls (top and right walls)
+  const torchRadius = 60;
+  // Torch 1: top wall, 1/3 width from left
+  const torch1X = x + w / 3;
+  const torch1Y = y + 10;
+  drawTorchGlow(ctx, torch1X, torch1Y, torchRadius, frame);
+
+  // Torch 2: right wall, 2/3 height from top
+  const torch2X = x + w - 10;
+  const torch2Y = y + (h * 2) / 3;
+  drawTorchGlow(ctx, torch2X, torch2Y, torchRadius, frame);
+}
